challenges.solution:
uniform vec2 u_resolution;
out vec4 fragColor;

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec2 center = vec2(0.5, 0.5);

    float d = distance(uv, center);
    float brightness = 1.0 - d * 2.0;

    fragColor = vec4(brightness, brightness, brightness, 1.0);
}

